import{_ as t,o as r,c as o,a2 as a}from"./chunks/framework.CHeM0PsO.js";const g=JSON.parse('{"title":"Core Use Cases","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/product/core-use-cases.md","filePath":"sovereign-os/product/core-use-cases.md"}'),n={name:"sovereign-os/product/core-use-cases.md"};function s(i,e,l,c,h,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="core-use-cases" tabindex="-1">Core Use Cases <a class="header-anchor" href="#core-use-cases" aria-label="Permalink to &quot;Core Use Cases&quot;">​</a></h1><p><strong>Status:</strong> Draft<br><strong>Version:</strong> 0.1<br><strong>Phase:</strong> Milestone 01.2; not Phase 01</p><blockquote><p>These use cases remain valid for the later AI and capability milestone. Phase 01 is now limited to the <a href="./../roadmap/01-preview-poc.html">flashable Pi-hole image POC</a>.</p></blockquote><h2 id="uc-01-check-pi-hole-health" tabindex="-1">UC-01: Check Pi-hole Health <a class="header-anchor" href="#uc-01-check-pi-hole-health" aria-label="Permalink to &quot;UC-01: Check Pi-hole Health&quot;">​</a></h2><p><strong>User intent:</strong> Determine whether DNS filtering is operating normally.<br><strong>Successful outcome:</strong> The system reports what it can verify about Pi-hole connectivity and health, with a timestamp and clear limits.<br><strong>Failure behavior:</strong> Distinguish Pi-hole unavailable, authentication failed, incompatible API, and Sovereign OS integration failure. <strong>Permissions:</strong> Read-only Pi-hole health access.<br><strong>Internet dependency:</strong> None when Pi-hole and the selected AI path are local; otherwise only the AI response generation may require internet.</p><h2 id="uc-02-review-blocked-request-count" tabindex="-1">UC-02: Review Blocked Request Count <a class="header-anchor" href="#uc-02-review-blocked-request-count" aria-label="Permalink to &quot;UC-02: Review Blocked Request Count&quot;">​</a></h2><p><strong>User intent:</strong> Understand how many DNS requests Pi-hole blocked during the relevant reporting period.<br><strong>Successful outcome:</strong> Return the count, the reporting period, and enough context to avoid misleading interpretation.<br><strong>Failure behavior:</strong> Never fabricate a count; explain unavailable or incomplete data.<br><strong>Permissions:</strong> Read-only Pi-hole statistics access.<br><strong>Privacy:</strong> Avoid persisting detailed query history merely to answer the question.</p><h2 id="uc-03-identify-high-volume-clients" tabindex="-1">UC-03: Identify High-Volume Clients <a class="header-anchor" href="#uc-03-identify-high-volume-clients" aria-label="Permalink to &quot;UC-03: Identify High-Volume Clients&quot;">​</a></h2><p><strong>User intent:</strong> See which local clients generate the most DNS traffic.<br><strong>Successful outcome:</strong> Return a bounded, ranked summary with the time period and naming limitations.<br><strong>Failure behavior:</strong> Explain when client identity is unavailable or ambiguous.<br><strong>Permissions:</strong> Read-only Pi-hole statistics access.<br><strong>Privacy:</strong> Client identifiers are sensitive household metadata and should not appear in ordinary logs.</p><h2 id="uc-04-explain-a-blocked-domain" tabindex="-1">UC-04: Explain a Blocked Domain <a class="header-anchor" href="#uc-04-explain-a-blocked-domain" aria-label="Permalink to &quot;UC-04: Explain a Blocked Domain&quot;">​</a></h2><p><strong>Status:</strong> Preview stretch goal.<br><strong>User intent:</strong> Understand whether and why a domain is blocked.<br><strong>Successful outcome:</strong> Report the observed blocking state and the responsible list or rule when the API can establish it.<br><strong>Failure behavior:</strong> Separate “not observed,” “not blocked,” and “cannot determine.”<br><strong>Permissions:</strong> Read-only Pi-hole query and list inspection.<br><strong>Safety:</strong> The preview must not automatically allowlist the domain.</p><h2 id="uc-05-check-sovereign-os-health" tabindex="-1">UC-05: Check Sovereign OS Health <a class="header-anchor" href="#uc-05-check-sovereign-os-health" aria-label="Permalink to &quot;UC-05: Check Sovereign OS Health&quot;">​</a></h2><p><strong>User intent:</strong> Determine whether the local platform and its required dependencies are operating.<br><strong>Successful outcome:</strong> Show core runtime, AI provider, Pi-hole integration, and relevant resource status.<br><strong>Failure behavior:</strong> Preserve dashboard access where possible and identify the failed dependency.<br><strong>Permissions:</strong> Read-only platform diagnostics.</p><h2 id="uc-06-handle-an-unsupported-request" tabindex="-1">UC-06: Handle an Unsupported Request <a class="header-anchor" href="#uc-06-handle-an-unsupported-request" aria-label="Permalink to &quot;UC-06: Handle an Unsupported Request&quot;">​</a></h2><p><strong>User intent:</strong> Ask something outside the preview&#39;s capability set.<br><strong>Successful outcome:</strong> Explain that the action is unsupported, avoid pretending it occurred, and identify supported alternatives where helpful.<br><strong>Safety:</strong> The AI must not improvise shell commands, generic network requests, or unregistered tool calls.</p><h2 id="uc-07-answer-a-current-question-with-web-search" tabindex="-1">UC-07: Answer a Current Question with Web Search <a class="header-anchor" href="#uc-07-answer-a-current-question-with-web-search" aria-label="Permalink to &quot;UC-07: Answer a Current Question with Web Search&quot;">​</a></h2><p><strong>User intent:</strong> Ask a question that cannot be answered reliably from local knowledge or registered household capabilities.</p><p><strong>Successful outcome:</strong> After explicit search authorization, the system sends a minimal visible query through the local SearXNG provider, returns an answer with inspectable source links, and distinguishes retrieved evidence from model knowledge.</p><p><strong>Failure behavior:</strong> Explain when search is disabled, offline, blocked by an upstream engine, or insufficient to support an answer. Do not fabricate sources.</p><p><strong>Permissions:</strong> <code>web.search</code>, followed by constrained <code>web.fetch</code> only when required.</p><p><strong>Privacy:</strong> Search terms leave the device for configured upstream engines. The system must not silently add conversation history, DNS data, device names, or other household context to the query.</p><h2 id="evaluation-rules" tabindex="-1">Evaluation Rules <a class="header-anchor" href="#evaluation-rules" aria-label="Permalink to &quot;Evaluation Rules&quot;">​</a></h2><p>Every use case should be tested for:</p><ul><li>successful response;</li><li>unavailable dependency;</li><li>invalid or incomplete input;</li><li>unauthorized access;</li><li>malformed model-generated tool call;</li><li>timeout;</li><li>privacy-safe logging;</li><li>understandable user-facing explanation.</li></ul>',24)])])}const p=t(n,[["render",s]]);export{g as __pageData,p as default};
